const statsRaw = $('Fetch Geo Stats (7 days)').first().json;
const minBidsRaw = $('Fetch Min Bids').first().json;

const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);
const minBids = minBidsRaw?.data?.result?.data || minBidsRaw?.data || (Array.isArray(minBidsRaw) ? minBidsRaw : []);

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No geo stats data' } }];
}

// Build min bids map
const minBidMap = {};
if (Array.isArray(minBids)) {
  minBids.forEach(mb => {
    minBidMap[mb.country_code] = {
      min: Number(mb.min_bid) || 0.001,
      recommended: Number(mb.recommended_bid) || 0.005
    };
  });
}

const maxCeiling = Number(0.10);

// Group stats by ad_id, then by country
const adGeoStats = {};
stats.forEach(d => {
  const adId = d.ad_id;
  const country = d.country_code;
  if (!adId || !country) return;

  if (!adGeoStats[adId]) adGeoStats[adId] = {};
  if (!adGeoStats[adId][country]) {
    adGeoStats[adId][country] = { spend: 0, revenue: 0, clicks: 0, shows: 0 };
  }

  adGeoStats[adId][country].spend += Number(d.money) || 0;
  adGeoStats[adId][country].revenue += Number(d.postbacks_confirmed_money) || 0;
  adGeoStats[adId][country].clicks += Number(d.clicks_count) || 0;
  adGeoStats[adId][country].shows += Number(d.shows_count) || 0;
});

const results = [];

for (const adId of Object.keys(adGeoStats)) {
  const geoBids = {};
  const details = [];

  for (const country of Object.keys(adGeoStats[adId])) {
    const g = adGeoStats[adId][country];
    const roi = g.spend > 0 ? ((g.revenue - g.spend) / g.spend * 100) : 0;
    const ctr = g.shows > 0 ? (g.clicks / g.shows * 100) : 0;
    const minBid = minBidMap[country]?.min || 0.001;
    const recBid = minBidMap[country]?.recommended || 0.005;

    // Calculate optimal bid based on ROI
    let optimalBid = recBid;
    if (roi > 50 && g.clicks > 10) {
      optimalBid = recBid * 1.5; // Scale profitable geos
    } else if (roi > 0 && g.clicks > 5) {
      optimalBid = recBid * 1.1;
    } else if (roi < -30 && g.clicks > 10) {
      optimalBid = minBid; // Minimize losing geos
    } else if (roi < -50 && g.spend > 2) {
      optimalBid = 0; // Effectively disable this geo
    }

    // Enforce bounds
    if (optimalBid > maxCeiling) optimalBid = maxCeiling;
    if (optimalBid > 0 && optimalBid < minBid) optimalBid = minBid;

    if (optimalBid > 0) {
      geoBids[country] = Math.round(optimalBid * 10000) / 10000;
    }

    details.push({
      country, roi: Math.round(roi * 100) / 100,
      clicks: g.clicks, spend: Math.round(g.spend * 100) / 100,
      bid: geoBids[country] || 0
    });
  }

  // API only supports one_bid_for_all_geo, so calculate weighted average
  const totalClicks = details.reduce((s, d) => s + d.clicks, 0);
  let weightedBid = 0;
  if (totalClicks > 0) {
    details.forEach(d => {
      if (d.bid > 0) weightedBid += d.bid * (d.clicks / totalClicks);
    });
  } else {
    const bids = details.filter(d => d.bid > 0).map(d => d.bid);
    weightedBid = bids.length > 0 ? bids.reduce((s, b) => s + b, 0) / bids.length : 0;
  }

  if (weightedBid > 0) {
    results.push({
      json: {
        ad_id: Number(adId),
        one_bid_for_all_geo: Math.round(weightedBid * 10000) / 10000,
        details: details
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No geo bid changes needed' } }];
}

return results;
